var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"내 연구실에 온 걸 환영하네, 엠버 박사.","JPN":"我が研究室にようこそ、アンバー博士。","ENG":"Welcome to my lab, Dr. Ember.","TWN":"琥珀博士，歡迎你來到我的研究室。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"아들내미 말로는 이번에도 다른 과학자들과 한바탕 했다던데……. 신수가 훤하구만.","JPN":"息子の話では、今回も他の科学者たちと派手にやりあったと聞いたが……\\nずいぶんと機嫌が良さそうだな。","ENG":"I heard from my son that you did a number on the other scientists? I like your style.","TWN":"我聽小犬說，這次博士和其他科學家又有些意見是嗎……真是有活力呢～"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"오랜만이네요. 회장님.","JPN":"お久しぶりです、会長。","ENG":"Good to see you again, sir.","TWN":"會長，好久不見。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"이번에 인수한 기업 사장이 회사 건물에서 투신했다면서요?","JPN":"今回買収した企業の社長が、会社から飛び降りたらしいですね。","ENG":"I heard that the former president of the company that you took over jumped from the company building.","TWN":"我聽說會長這次接手的公司，那個老闆從公司一躍而下？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"애도라도 표하셨나 모르겠네요. 뉴스 본 지도 오래돼서.","JPN":"哀悼はしましたか？　ニュースはしばらく見ていないので。","ENG":"Did you send your condolences? I haven't watched the news in a long time.","TWN":"不知道會長有為他哀悼嗎？雖然我是很久以前在新聞上看到的。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"그놈이 회사를 좀 맡아 주십쇼, 하고 빌길래 사들인 건데 내가 왜 애도를 표하나?","JPN":"あいつから自分の会社をお願いしたいとすがりつくから買ってやったのに、\\nなぜ私が心を痛めねばならんのだ？","ENG":"He’s the one who begged me to take it from him. Why should I pay him my respect?","TWN":"是那傢伙來求我接收他的公司的，我有什麼好哀悼的？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"시장은 먹고 먹히는 곳이야. 누가 인수하려고 마음 먹었나 싶으면 대비를 해야지.","JPN":"喰って、喰われる業界だ。誰かに買収されるとわかったなら、それに備えなければな。","ENG":"It’s a dog-eat-dog world out there. When he heard that someone was attempting to take over, he should have prepared.","TWN":"做生意本來就是彼此勾心鬥角，要是發現有人想收購公司，就必須事先想好對策，超前佈署。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"언론에서 비난하는 건 회장님이 인수 전에 하신 밑준비 같던데요.","JPN":"マスコミが非難しているのは、会長が買収前にした下準備のことだそうですが。","ENG":"Isn't it the preparation for the merger that the media is criticizing you for?","TWN":"輿論上說會長是有計畫收購人家公司的呢？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"……그놈 가족에게는 내 넉넉히 챙겨 줬어. 그러니 더 말 말게.","JPN":"……奴の家族には十分なほど渡してやった。だからこれ以上は言わないでくれ。","ENG":"I gave his family a hefty settlement check. Now, enough talk about this.","TWN":"……我可沒有虧待他的家人，這沒什麼好再說的。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"고약한 성질머리는 여전하시군요.","JPN":"人間味がないのは相変わらずですね。","ENG":"I see you’re hot-headed as usual.","TWN":"會長的脾氣還是那麼硬呢～"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"나와 말싸움이나 하자고 온 건가?","JPN":"私と口論をするために来たのか？","ENG":"Have you come here to argue with me?","TWN":"你是來和我吵架的嗎？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"아뇨. 위기관리 부서에서 강탈한 출처불명의 유전체 지도를 보러 왔습니다.","JPN":"いいえ。危機管理部から強奪した、出所不明のゲノム地図を見に来ました。","ENG":"No, sir. I’ve come to see the unidentified genome map that you stole from the Crisis Management Department.","TWN":"不是的，我是來欣賞被危機管理部門搶走的，來路不明的基因圖譜。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"요정을 만드는 방법이라느니 어쩌니 하던데……. 직접 들여다본 다음 판단하고 싶어서요.","JPN":"『妖精』の作り方がどうのと聞きましたが……直接見て判断したいです。","ENG":"I heard rumors of it containing a method to create fairies, but I wanted to see for myself before passing judgment.","TWN":"似乎跟製造精靈，還什麼的有關……我想親自來確認後再判斷。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"눈치도 빠르군. 언론에는 정신 나간 재야학자가 소란 피운 걸로 나갔을 텐데…….","JPN":"目ざといな。マスコミにはイカれた民間学者が騒ぎ立てたと流したはずだが……","ENG":"Well aren’t you quick-witted. I heard the media reported it as a hysterical scientist's outburst...","TWN":"觀察力不錯嘛，媒體上的報導應該只有提到，某個瘋狂科學家引起騷動吧……"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"그래도 마침 잘 왔네.","JPN":"それにしてもちょうどいいところに来た。","ENG":"But I’m glad you came.","TWN":"不過你來得正是時候！"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"그분에게 도저히 물을 방도가 없어서 자네를 부르려 하던 참이니까.","JPN":"あの方にお伺いするすべがなくて、君を呼ぼうとしたところだったんだ。","ENG":"I couldn’t find a way to reach The Eminent, so I was about to call you.","TWN":"因為我實在是沒有方法可以問到他，正想找你來問問！"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"그분이 누군지는 모르겠지만…… 직원들 보는 앞에서 회장님 얼굴에 파스타를 던진 저를요?","JPN":"あの方が誰かはわかりませんが……\\n社員たちの前で会長の顔にパスタを投げつけた私をですか？","ENG":"I don’t know who you’re talking about, but... you wanted to see me? The girl who threw pasta at her boss’ face in front of everyone?","TWN":"雖然不清楚那個他是指誰……但會長怎麼會想找我？我可是在員工面前，把義大利麵砸在會長臉上呢？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"능력 있는 인재라면 얼굴에 파스타를 던지든 머리털에 불을 붙이든 무슨 상관인가.","JPN":"優れた人材なら顔にパスタを投げつけようが、髪の毛に火をつけようが関係ない。","ENG":"If you have the skills to back it up, it doesn’t matter if you throw pasta or set your boss’ hair on fire.","TWN":"只要是有能力的人才，要在我臉上扔義大利麵，或是在我頭上點火，我都無所謂。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"단도직입적으로 말하지. 내가 진행 중인 특이점 프로젝트에 자네가 참여해 줬으면 하네.","JPN":"単刀直入に言おう。私が進行している特異点プロジェクトに参加してほしい。","ENG":"Let me be direct with you. I want you to join my Singularity Project.","TWN":"我就直說了吧，我希望你能加入正在進行中的奇異點計畫。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"……특이점?","JPN":"……特異点？","ENG":"...Singularity?","TWN":"……奇異點？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"갑자기 수학에 취미를 붙이셨을 리는 없고…… 무엇에 대한 특이점이죠?","JPN":"急に数学への興味を持たれたとも思えませんが……\\n何に対する特異点ですか？","ENG":"I know you have no interest in mathematics... So what Singularity are we talking about?","TWN":"會長應該不是突然對數學感興趣吧…… 是關於什麼的奇異點？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"<color=#ffd34c>인간</color>.","JPN":"<color=#ffd34c>人間</color>。","ENG":"<color=#ffd34c>Human</color>.","TWN":"<color=#ffd34c>人類</color>。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"예전에 아들내미가 내게 그러더군.","JPN":"以前、息子が私にこう言った。","ENG":"My son once said to me,","TWN":"以前小犬跟我說過，"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"인공지능의 지적 능력이 인간이란 종의 최대 지적 능력을 뛰어넘는 순간을 특이점이라고 부른다고.","JPN":"人工知能の知的能力が、人間という種の最大知的能力を\\n越える瞬間を特異点と呼ぶ、と。","ENG":"that Singularity occurs when the intelligence of A.I. exceeds the maximum intelligence of the human species.","TWN":"他說人工智慧的智力超過人類的瞬間就稱為奇異點。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"재밌는 이야기야. 확실히 그건 더 이상 기계라고 할 수 없는 다른 뭔가겠지.","JPN":"面白い話だ。確かに、それはもはや機械とは呼べない別のなにかだろう。","ENG":"It’s a fascinating subject. But I have to admit that whatever \\"that\\" is, it can’t be machine.","TWN":"很有意思的說法，這樣確實無法再單純地稱之為機械。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"박사의 그 진화하는 인공지능도 그런 것 아닌가?","JPN":"博士が作っている進化する人工知能も似たようなものだろう？","ENG":"Isn’t your evolving A.I something similar, doctor?","TWN":"博士那個進化的人工智慧也是如此吧？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"그 이야기가 여기서 벌어지는 연구와 무슨 관련이 있을지 모르겠네요.","JPN":"その話がここで行われている研究と何の関係があるのか、\\nさっぱりわかりませんね。","ENG":"I'm not sure if that has anything to do with the research that's being conducted here.","TWN":"我不太明白這件事跟會長剛說的計畫有什麼關係？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"지금까지 인간을 복제하려는 시도는 수없이 많았지.","JPN":"これまで人間を複製しようとする試みは、数え切れないほど行われていた。","ENG":"Humans have tried countless times to clone themselves.","TWN":"至今已經做過無數次複製人類的嘗試，"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"하지만 인간이란 결점투성이야.","JPN":"だが、人間は欠点だらけだ。","ENG":"But what we call human is flawed.","TWN":"但人類就是不完美，是有缺點的。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"양계장의 닭처럼 자기들끼리 모여 살 때는 숨길 수 있을지 몰라도……","JPN":"養鶏場の鶏のように、自分たちだけで集まって暮らしていれば\\n隠し通せるのかもしれないが……","ENG":"They may be able to hide it when they live together, like chickens in a chicken coop...","TWN":"就像養雞場的雞一樣，群體生活在一起時，還可以藏起來……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"들고양이 한 마리만 들이닥치면 얼마나 겁 많고 연약한지 탄로나 버린다네.","JPN":"野良猫が1匹でも入ってきてしまえば、\\n自分たちがどれだけ臆病で、か弱い存在なのかすぐバレてしまう。","ENG":"but once a wild cat approaches, it’s revealed how cowardly and fragile they really are.","TWN":"但只要遇到一隻野貓，就會完全呈現出懦弱膽小的一面。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"그건 닭이란 종의 근본적인 한계야. 그걸 진화로 뛰어넘기엔…….","JPN":"それは鶏という種の根本的な限界だ。それを進化で乗り越えようにも……","ENG":"That's the fundamental limitation of the chicken. But to evolve and go beyond...","TWN":"那是雞本身的限制，要透過進化去克服可能……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"이 세상은 지금도 지나치게 위험으로 가득차 있어.","JPN":"今もこの世界はあらゆる危険に満ちている。","ENG":"The world is still too dangerous to take that leap.","TWN":"這個世界目前還是充滿著危險。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"……요즘 더 괴팍해지셨다더니 정말이군요.","JPN":"……最近はさらに偏屈になったと聞きましたが、本当だったんですね。","ENG":"So it's true about how you've become more eccentric these days.","TWN":"……我聽說會長最近變得更古怪，看來是真的呢。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"그럼 회장님은 인간에게 뭐가 필요하다고 생각하시죠?","JPN":"では、会長は人間に何が必要だと思いますか？","ENG":"Then sir, what do you think humans need?","TWN":"那我想請問會長，你覺得人類需要的是什麼？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"<color=#ffd34c>혁신</color>이지.","JPN":"<color=#ffd34c>革新</color>だ。","ENG":"<color=#ffd34c>Innovation</color>.","TWN":"<color=#ffd34c>革新</color>。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"결함투성이의 설계는 버리고, 애초에 결함이 없는 새로운 인간을 만들어내는 거야.","JPN":"欠陥だらけの設計は捨てて、最初から欠陥のない\\n新しい人間を創り出すのだ。","ENG":"We must abandon the crude design and create a new human species that is flawless from birth.","TWN":"要丟掉有缺陷的設計，創造出原本毫無瑕疵的全新人類！"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"그래서……. 그 혁신이 <color=#ffd34c>저것</color>이고 말이죠.","JPN":"それで……その革新が<color=#ffd34c>アレ</color>なんですね。","ENG":"And... this innovation is <color=#ffd34c>that</color> over there?","TWN":"所以……會長所謂的革新，就是指<color=#ffd34c>那個</color>是吧？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"그렇지. 설화 속 요정처럼 내 상상을 실현해 줄 <color=#ffd34c>만능의 인간</color>.","JPN":"そうだ。物語に出てくる妖精のように、私の想像を実現してくれる<color=#ffd34c>万能な人間</color>。","ENG":"An <color=#ffd34c>omnipotent being</color> who, like a fairy in a fairy tale, will bring my imagination to life.","TWN":"沒錯，就像童話故事裡的精靈一樣，可以實現我的想像的<color=#ffd34c>無所不能的人類</color>。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"상상할 수 있는 모든 위험에 대처 가능한 저것이야말로, 바로 내가 추구하는 특이점일세.","JPN":"想像しうるあらゆる危険に対応できるアレこそが、\\nまさに私が追求する特異点だ。","ENG":"The singularity I seek is the ability to deal with any conceivable risk.","TWN":"能夠應對所有想像得到的危險，那個才是我所追求的奇異點！"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"프로젝트는 이제 막바지라네.","JPN":"プロジェクトは最終段階に差しかかった。","ENG":"The project is in its last phases.","TWN":"現在計畫已經來到最後的階段。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"기대 수명이 짧다는 단점만 해결하면 우린 더 이상 이면세계를 두려워할 필요가 없어.","JPN":"期待寿命が短いという欠点さえ解決できれば、我々はこれ以上\\n裏世界を恐れる必要はない。","ENG":"Once we have resolved the issue of its short life expectancy, we no longer have to fear the Counterside.","TWN":"只要解決壽命過短的問題，我們就不需要再對異界感到恐懼！"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"카운터들 없이도, 저것들을 양산한다면 침식체는 걱정거리도 안 될 테니 말일세.","JPN":"カウンターがいなくても、アレを量産すれば侵食体なんて\\n脅威にもならないだろう。","ENG":"We will no longer need Counters, nor have to worry about Corrupted Objects once these are mass produced.","TWN":"就算沒有制裁者，只要將那個量產，就不需要再擔心侵蝕體的問題！"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"지루한 연설은 열심히 들었습니다만…….","JPN":"退屈なスピーチを熱心に拝聴させていただきましたが……","ENG":"Thank you for that long and boring speech, but...","TWN":"我很努力聽完你的長篇大論……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"그렇게 대단한 존재가 회장님 말을 순순히 따를까요?","JPN":"そんな高みにいる存在が会長の言うことを素直に聞くと思いますか？","ENG":"Are you certain that this absolute being will obey your every command?","TWN":"但會長認為，那個那麼厲害，那他會乖乖地聽會長的話嗎？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"바로 그걸세. 자네 머리를 빌리고 싶은 부분이.","JPN":"まさにそれだ。君の頭脳を借りたい部分は。","ENG":"That’s exactly why I want you to join this project, doctor.","TWN":"你問得很好，這就是我想找你加入的原因！"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"……아직 쿠키 영상이 남아 있었군요. 말씀해 보시죠.","JPN":"……まだ続きがあったんですね。はい、どうぞ。","ENG":"I guess there was a second part to the speech. Please continue.","TWN":"……原來還有彩蛋，會長請說。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"아무리 하드웨어가 뛰어나도 사용자 경험이 뒷받침되지 않으면 못 쓸 물건이지.","JPN":"いくらハードウェアが優れていても、ソフトウェアが伴わなければ\\n使い物にならない。","ENG":"No matter how good the hardware is, it is virtually useless unless it is accompanied by user experience.","TWN":"就算硬體很厲害，也必須仰賴使用者的操作經驗，否則完全派不上用場。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"설계 단계에서 이미 나를 명령권자로 인식하게 설정해 두었네만…….","JPN":"設計段階から私を命令権者として認識するように設定しておいたが……","ENG":"It has already been set during the design phase to recognize me as the administrator...","TWN":"在設計時，雖然有先設定成會識別我的指令……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"자식들 꼴을 보고 나니 교육에는 자신이 없어. 그나마 멀쩡한 아들내미도 저 혼자 큰 거지.","JPN":"うちの子どもたちの様子を見る限り、教育には自信がなくてね。\\nまともな息子もいるが、勝手に一人で育ったわけだしな。","ENG":"But, after seeing how my children are, I am not confident in my ability to educate it. My eldest is the only good example. But then again, I had no part in his growing up.","TWN":"但我自己的孩子是那副德性，我實在是對教育沒有信心，就連唯一一個還可以的兒子，也不是我教出來的。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"그러니 자네가 도와 주게. 이것들이 올바른 가치관만 가지고, 올바른 행동만 할 수 있도록.","JPN":"だから君の手を貸してくれ。これらが正しい価値観だけを持ち、\\n正しい行動だけができるように。","ENG":"I require your assistance. Teach it so that it only knows virtue and will act accordingly.","TWN":"所以我想找你幫忙，讓他們可以有正確的價值觀和行為！"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"……일단 지원금을 받는 입장에서 되도록 참고 있었습니다만.","JPN":"……一応補助金をいただいてる立場なので、ギリギリまで\\n口を謹んでいたのですが。","ENG":"You know, I was keeping my mouth shut because I need your funding, but...","TWN":"……畢竟我有拿會長的經費，所以我才一直耐著性子聽你說這些。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"지금 사람 불러 놓고 얼마나 미친 소리를 늘어놓고 있는지 아시나요?","JPN":"急に呼び出しておいて、ご自身がどれだけとんだ戯言を並べているのか、\\n自覚はありますか？","ENG":"Do you have any idea how crazy all of this sounds?","TWN":"你知道你現在說這些話有多麼荒謬嗎？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"미쳤다……. 미쳤다라…….","JPN":"とんだ戯言……戯言か……","ENG":"Crazy... Crazy, huh?","TWN":"荒謬……荒謬是嗎……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"<color=#ffd34c>더 나은 세상을 위해서</color>라면 그런 소리는 얼마든지 들을 수 있지.","JPN":"<color=#ffd34c>より良い世界のため</color>なら、そんなことはいくらでも聞いてやる。","ENG":"<color=#ffd34c>For a better world</color>, I’ll accept being the crazy one.","TWN":"只要是<color=#ffd34c>為了更好的未來</color>，就一點也不荒謬！"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"내가 할 줄 아는 건 돈벌이뿐이었지만…… 세상엔 돈으로 해결할 수 있는 일들도 많아.","JPN":"私にできることは金儲けだけだが……\\n世の中には、金で解決できないことも多い。","ENG":"All I know is making money, and a lot can be achieved with it.","TWN":"我是只會賺錢……但這個世界上，也有很多能夠用錢解決的事。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"이 세상은 위협으로 가득차 있어, 엠버 박사. 인류는 바뀌어야 해.","JPN":"世界は脅威に満ちているのだよ、アンバー博士。\\n人類は変わらなければならない。","ENG":"But danger lurks in this world, Dr. Ember. Humanity needs to change.","TWN":"這個世界充滿著威脅，琥珀博士。人類需要改變！"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"신 박사님이 이런 정신 나간 곳에 남아 계시겠다고 고집 부리신 게 이해가 안 되네요.","JPN":"ヒメノ博士がこんなイカれたところに残ると意地を張ったのが理解できませんね。","ENG":"I don’t understand why Dr. Shin decided to stay in this loony bin.","TWN":"我真不明白，沈博士為何堅持要留在這個不正常的地方？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"아, 그럼. 아들내미 없이는 프로젝트도 시작하지 못 했겠지.","JPN":"ああ、そうとも。息子がいなければプロジェクトを始めることすら\\nできなかっただろう。","ENG":"Ah, yes. I couldn’t have done this without my son.","TWN":"那當然，要是沒有小犬，這個計畫也不會開始。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"내외가 불임이라 말일세. 자식 대신 저거에 정을 붙였나 보더군.","JPN":"息子夫婦は不妊でな。子どもの代わりにアレに愛着が湧いたようだ。","ENG":"They are a couple who are infertile. So it appears that he formed a bond with that as if it were his own child.","TWN":"可能因為他們不孕吧，所以將對孩子的期待，都轉移到這上面。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"그래서, 제안을 받아들이겠나?","JPN":"で、提案を受け入れてくれるのか？","ENG":"So, will you accept my proposal?","TWN":"如何？你願意接受我的邀請嗎？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"거절하겠습니다.","JPN":"お断りします。","ENG":"I will not accept.","TWN":"我拒絕。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"도구로 쓸 인간을 만들겠다는 정신 나간 발상에 맞장구치긴 힘들어서요.","JPN":"道具として使う人間を作るなんてイカれた発想に付き合うのはご免です。","ENG":"It's difficult to agree with the insane idea of creating a human-tool.","TWN":"竟然想製造作可以當作工具使用的人類，這麼瘋狂的想法，我完全無法認同。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"아쉽군. 우린 더 나은 세상을 만들려는 동지라고 생각했는데.","JPN":"残念だな。私たちはより良い世界のためという同じ目的意識を持った仲間だと\\n思っていたのだが。","ENG":"How unfortunate. And here I thought we were pioneers of making the world a better place.","TWN":"真是遺憾，我還以為我們是同道中人，都是為了更好的未來。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"글쎄요. 이따위 방식으로 연명하겠다고 하는 사람이 있으면 전 정나미가 떨어질 것 같네요.","JPN":"どうでしょう。こんなやり方で延命しようとする人間がいるのなら、\\n私は愛想が尽きそうです。","ENG":"I strongly disagree. I'd be disgusted out of my mind if someone told me they wanted to live in a world like that.","TWN":"這個嘛，如果是用這種方式，那我情願選擇不要。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"가 보겠습니다, 회장님.","JPN":"もう帰りますよ、会長。","ENG":"Good bye, sir.","TWN":"會長，請恕我先行離開。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"다시는 마주칠 일 없으면 좋겠군요.","JPN":"もう二度とお会いしたくないですね。","ENG":"I hope we never meet again.","TWN":"希望我們不會再見面。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}}]`);export{e as default};